// Parse + Auth — Việc VERIFY token đã do node "🔐 Verify JWT" (Cách B, HTTP /auth/v1/user) thực hiện.
// Node này CHỈ lấy sub (cho truy vấn DB) + đọc & validate body theo mode. Không phải cổng xác thực.
const headers = $('Webhook Literature Search').first().json.headers || {};
const body = $('Webhook Literature Search').first().json.body || {};
const token = (headers.authorization || headers.Authorization || '').replace('Bearer ', '');
if (!token) return [{ json: { error: true, message: 'Thiếu token', status: 401 } }];
let userId;
try { userId = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString()).sub; if (!userId) throw 0; }
catch (e) { return [{ json: { error: true, message: 'Token không hợp lệ', status: 401 } }]; }

const mode = (body.mode || 'search').toLowerCase();
// Europe PMC bao trùm MEDLINE/PubMed + có abstract + open access → engine mặc định.
const database = (body.database || 'europepmc').toLowerCase();
if (mode !== 'search' && mode !== 'ingest') {
  return [{ json: { error: true, message: "mode phải là 'search' hoặc 'ingest'", status: 400 } }];
}

if (mode === 'search') {
  const q = (body.query || body.q || '').toString().trim();
  if (!q) return [{ json: { error: true, message: 'Thiếu query tìm kiếm (body.query)', status: 400 } }];
  let pageSize = parseInt(body.page_size || body.limit || 10, 10);
  if (isNaN(pageSize) || pageSize < 1) pageSize = 10;
  if (pageSize > 25) pageSize = 25;
  const openAccessOnly = body.open_access_only === true;
  const sort = (body.sort || 'relevance').toLowerCase(); // 'relevance' | 'date'
  return [{ json: {
    error: false, mode, database, user_id: userId,
    query: q, page_size: pageSize, open_access_only: openAccessOnly, sort
  } }];
}

// mode === 'ingest' (nạp 1 bài đã chọn vào kho — chỉ QA/Admin, sẽ kiểm role ở bước sau)
const pmid = (body.pmid || '').toString().trim();
const doi = (body.doi || '').toString().trim();
if (!pmid && !doi) return [{ json: { error: true, message: 'Ingest cần body.pmid hoặc body.doi', status: 400 } }];
const docCode = body.document_code
  || (pmid ? ('PMID-' + pmid) : ('DOI-' + doi.replace(/[^A-Za-z0-9._-]/g, '_')));
let trust = parseInt(body.trust_level, 10); if (isNaN(trust)) trust = 2; // peer-reviewed literature = 2
const lang = ['vi', 'en', 'vi-en', 'other'].includes(body.language_code) ? body.language_code : 'en';
return [{ json: {
  error: false, mode, database, user_id: userId,
  pmid, doi, document_code: docCode, language_code: lang, trust_level: trust
} }];

// Build URL tìm kiếm Europe PMC (REST công khai, không cần key).
const p = $json;
const base = 'https://www.ebi.ac.uk/europepmc/webservices/rest/search';
let q = p.query;
if (p.open_access_only) q = '(' + q + ') AND OPEN_ACCESS:Y';
const sortParam = p.sort === 'date' ? '&sort=' + encodeURIComponent('P_PDATE_D desc') : '';
const url = base + '?query=' + encodeURIComponent(q)
  + '&format=json&resultType=core&pageSize=' + p.page_size + sortParam;
return [{ json: { ...p, search_url: url } }];

// Chuẩn hoá kết quả Europe PMC → danh sách có trích dẫn (title, authors, journal, year, DOI/PMID, abstract, url)
const p = $('Build Search URL').first().json;
const resp = $input.first().json;
const list = (resp.resultList && resp.resultList.result) || [];

function articleUrl(r) {
  if (r.doi) return 'https://doi.org/' + r.doi;
  if (r.pmid) return 'https://pubmed.ncbi.nlm.nih.gov/' + r.pmid + '/';
  if (r.pmcid) return 'https://www.ncbi.nlm.nih.gov/pmc/articles/' + r.pmcid + '/';
  if (r.id && r.source) return 'https://europepmc.org/article/' + r.source + '/' + r.id;
  return null;
}
function clean(s) { return (s || '').toString().replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim(); }

const results = list.map((r, i) => {
  const authors = clean(r.authorString);
  const journal = clean(r.journalTitle || (r.journalInfo && r.journalInfo.journal && r.journalInfo.journal.title));
  const title = clean(r.title);
  const ab = clean(r.abstractText);
  let cite = '[' + (i + 1) + '] ' + (authors ? authors + '. ' : '') + (title ? title + '. ' : '')
    + (journal ? journal + '. ' : '') + (r.pubYear ? '(' + r.pubYear + ') ' : '')
    + (r.doi ? 'doi:' + r.doi + ' ' : '') + (r.pmid ? 'PMID:' + r.pmid : '');
  return {
    rank: i + 1,
    title,
    authors,
    journal,
    year: r.pubYear || null,
    pmid: r.pmid || null,
    pmcid: r.pmcid || null,
    doi: r.doi || null,
    source: r.source || null,
    is_open_access: r.isOpenAccess === 'Y' || r.inEPMC === 'Y',
    citation: cite.replace(/\s+/g, ' ').trim(),
    abstract: ab ? (ab.length > 1200 ? ab.slice(0, 1200) + '…' : ab) : '',
    url: articleUrl(r)
  };
});

return [{ json: {
  success: true,
  mode: 'search',
  database: p.database,
  query: p.query,
  count: results.length,
  hit_count_total: resp.hitCount || results.length,
  results
} }];

const roles=$input.all().map(i=>i.json.role_name);
const prev=$('Parse + Auth').first().json;
if(!roles.some(r=>['admin','qa_manager'].includes(r))) return [{json:{error:true,message:'Chỉ QA Manager/Admin được nạp literature vào kho AI',status:403}}];
return [{json:{...prev,primary_role:roles[0]}}];

function sha256Hex(input){
  let msg;
  if (typeof input==='string') msg=new TextEncoder().encode(input);
  else if (input instanceof Uint8Array) msg=input;
  else if (typeof Buffer!=='undefined' && Buffer.isBuffer(input)) msg=new Uint8Array(input);
  else msg=new TextEncoder().encode(String(input));
  const K=new Uint32Array([0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2]);
  let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;
  const l=msg.length;
  const bitLenHi=Math.floor(l/0x20000000)>>>0;
  const bitLenLo=(l<<3)>>>0;
  const withOne=l+1;
  const k=(56-(withOne%64)+64)%64;
  const total=withOne+k+8;
  const m=new Uint8Array(total); m.set(msg,0); m[l]=0x80;
  const dv=new DataView(m.buffer);
  dv.setUint32(total-8,bitLenHi); dv.setUint32(total-4,bitLenLo);
  const w=new Uint32Array(64);
  const rotr=(x,n)=>((x>>>n)|(x<<(32-n)))>>>0;
  for(let off=0;off<total;off+=64){
    for(let i=0;i<16;i++) w[i]=dv.getUint32(off+i*4);
    for(let i=16;i<64;i++){
      const s0=(rotr(w[i-15],7)^rotr(w[i-15],18)^(w[i-15]>>>3))>>>0;
      const s1=(rotr(w[i-2],17)^rotr(w[i-2],19)^(w[i-2]>>>10))>>>0;
      w[i]=(w[i-16]+s0+w[i-7]+s1)>>>0;
    }
    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;
    for(let i=0;i<64;i++){
      const S1=(rotr(e,6)^rotr(e,11)^rotr(e,25))>>>0;
      const ch=((e&f)^((~e)&g))>>>0;
      const t1=(h+S1+ch+K[i]+w[i])>>>0;
      const S0=(rotr(a,2)^rotr(a,13)^rotr(a,22))>>>0;
      const maj=((a&b)^(a&c)^(b&c))>>>0;
      const t2=(S0+maj)>>>0;
      h=g;g=f;f=e;e=(d+t1)>>>0;d=c;c=b;b=a;a=(t1+t2)>>>0;
    }
    h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
  }
  const toHex=x=>('00000000'+(x>>>0).toString(16)).slice(-8);
  return toHex(h0)+toHex(h1)+toHex(h2)+toHex(h3)+toHex(h4)+toHex(h5)+toHex(h6)+toHex(h7);
}

// ==== BODY: normalize bài báo đơn (Europe PMC) + chunk + hash. sha256Hex() được builder chèn phía trên. ====
const prev = $('Check Permission').first().json;
const resp = $input.first().json;
const list = (resp.resultList && resp.resultList.result) || [];
if (!list.length) {
  return [{ json: { error: true, message: 'Không tìm thấy bài báo với PMID/DOI đã cho trên Europe PMC', status: 404 } }];
}
const r = list[0];
function clean(s) { return (s || '').toString().replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim(); }

const title = clean(r.title);
const abstract = clean(r.abstractText);
const authors = clean(r.authorString);
const journal = clean(r.journalTitle || (r.journalInfo && r.journalInfo.journal && r.journalInfo.journal.title));
const year = r.pubYear || null;
const doi = r.doi || prev.doi || null;
const pmid = r.pmid || prev.pmid || null;

// Nội dung embed = header trích dẫn + abstract (đủ ngữ cảnh cho RAG + giữ được citation)
const headerLine = title
  + (authors ? ' | ' + authors : '')
  + (journal ? ' | ' + journal : '')
  + (year ? ' | ' + year : '')
  + (doi ? ' | doi:' + doi : '')
  + (pmid ? ' | PMID:' + pmid : '');
const fullText = (headerLine + '\n\n' + (abstract || '(Không có abstract công khai)')).trim();
if (fullText.length < 40) {
  return [{ json: { error: true, message: 'Bài báo không có đủ nội dung (title/abstract) để index', status: 422 } }];
}

const fileHash = sha256Hex(fullText);

// Chunking (abstract thường ngắn → 1 chunk; vẫn chia nếu dài)
const CHUNK_SIZE = 1500, OVERLAP = 200;
let chunks = [], idx = 0, start = 0;
while (start < fullText.length) {
  let end = Math.min(start + CHUNK_SIZE, fullText.length);
  if (end < fullText.length) { const bp = fullText.lastIndexOf('.', end); if (bp > start + CHUNK_SIZE * 0.5) end = bp + 1; }
  const ct = fullText.substring(start, end).trim();
  if (ct) chunks.push({ content: ct, chunk_index: idx++, content_tokens: Math.ceil(ct.length / 3) });
  if (end >= fullText.length) break;
  start = end - OVERLAP; if (start < 0) start = 0;
}

const organization = prev.database === 'pubmed' ? 'PubMed' : 'Europe PMC';
const pubDate = year ? (String(year) + '-01-01') : null;
const sourceUrl = doi ? ('https://doi.org/' + doi) : (pmid ? ('https://pubmed.ncbi.nlm.nih.gov/' + pmid + '/') : null);

return [{ json: {
  ...prev,
  document_title: (title || prev.document_code).slice(0, 500),
  document_code: prev.document_code,
  organization, authors, journal, year, doi, pmid,
  publication_date: pubDate,
  source_url: sourceUrl,
  file_hash: fileHash,
  chunks,
  texts_for_embedding: chunks.map(c => c.content),
  total_chunks: chunks.length
} }];

// Tạo SQL INSERT documents cho bài báo literature (source_category='literature', source_type='guideline')
const embedResult = $input.first().json;
const prev = $('Normalize Article').first().json;
const embeddings = embedResult.data || [];
const esc = s => String(s == null ? '' : s).replace(/'/g, "''");

const groupId = 'LIT-' + prev.document_code;
const trust = parseInt(prev.trust_level, 10) || 2;
const docSQL = `INSERT INTO documents (document_group_id,document_code,document_title,document_type,language_code,source_type,source_category,trust_level,source_url,source_organization,publication_date,version,status,file_hash,uploaded_by,last_verified_at) VALUES ('${esc(groupId)}','${esc(prev.document_code)}','${esc(prev.document_title)}','guideline'::document_type,'${prev.language_code}'::language_code,'guideline'::source_type,'literature',${trust},${prev.source_url ? "'" + esc(prev.source_url) + "'" : 'NULL'},'${esc(prev.organization)}',${prev.publication_date ? "'" + prev.publication_date + "'" : 'NULL'},'01','indexed'::document_status,'${esc(prev.file_hash)}','${prev.user_id}'::uuid,now()) RETURNING id;`;

return [{ json: { docSQL, prev_data: prev, embeddings_json: JSON.stringify(embeddings.map(e => e.embedding)) } }];

// Build SQL INSERT document_chunks + cập nhật chunk_count + ghi audit (append-only, action document_index)
const docResult = $input.first().json;
const built = $('Build Doc SQL').first().json;
const prev = built.prev_data;
const docId = docResult.id;
const embeddings = JSON.parse(built.embeddings_json);
const esc = s => String(s == null ? '' : s).replace(/'/g, "''");
const trust = parseInt(prev.trust_level, 10) || 2;

let values = [];
for (let i = 0; i < prev.chunks.length; i++) {
  const c = prev.chunks[i];
  const emb = embeddings[i];
  const embStr = emb ? "'[" + emb.join(',') + "]'" : 'NULL';
  values.push(`('${docId}','${esc(c.content)}',${c.content_tokens},${c.chunk_index},NULL,'text','${esc(prev.document_code)}','01','${prev.language_code}'::language_code,'guideline'::source_type,'literature',${trust},'${esc(prev.organization)}','${esc(prev.file_hash)}',${embStr}::vector,'indexed'::document_status)`);
}

const summary = 'Literature ingest: ' + prev.document_code + ' (' + prev.organization + ') — ' + String(prev.document_title || '').slice(0, 120);
const chunksSQL = `INSERT INTO document_chunks (document_id,content,content_tokens,chunk_index,page_number,chunk_type,document_code,document_version,language_code,source_type,source_category,trust_level,source_organization,file_hash,embedding,status) VALUES ${values.join(',')};\nUPDATE documents SET chunk_count=${prev.chunks.length} WHERE id='${docId}'::uuid;\nSELECT write_audit_log('${prev.user_id}'::uuid,NULL,'${esc(prev.primary_role)}','document_index'::audit_action,'${esc(summary)}',NULL,NULL,'${docId}'::uuid,'${esc(prev.document_code)}');`;

return [{ json: { chunksSQL, document_id: docId, document_code: prev.document_code, title: prev.document_title, organization: prev.organization, total_chunks: prev.chunks.length } }];
